fr:mainmatter.fr:tex:
\begin {align*}
  \phi _t(z, b) &= \mathbb {P}(s_{0}, a_{0}, \ldots , s_{t}, z_{t} = z, b_{t} = b) \\
  \beta _t(z, b) &= \mathbb {P}(s_{t + 1}, a_{t + 1}, \ldots , s_{T} \mid  z_{t} = z, b_{t} = b),
.\end {align*}

\begin {align*}
  \phi _t(z, b) &= \mathbb {P}(s_t, a_t \mid  z, b) \sum _{(z', b')} \phi _{t - 1}(z', b') \mathbb {P}(z, b \mid  z', b') \\
  \beta _t(z, b) &= \sum _{(z', b')} \beta _{t + 1}(z', b') \mathbb {P}(s_{t + 1}, a_{t + 1} \mid  z', b')  \mathbb {P}(z', b' \mid  z, b)
.\end {align*}

\begin {align*}
  \mathbb {P}_{\theta }(z, b = 0 \mid  z') &= \delta _{\{z = z'\}} (1 - \psi _{\theta }(s_{t}, z')) \\
  \mathbb {P}_{\theta }(z, b = 1 \mid  z') &= \eta _{\theta }(z \mid  s_{t}) \psi _{\theta }(s_{t}, z')
.\end {align*}

\begin {align*}
  \phi _t(z, b) = \mathbb {P}_{\theta }(s_t, a_t \mid  z, b) \sum _{(z', b')} \phi _{t - 1}(z', b') \Big (&\eta _{\theta }(z \mid  s_{t}) \psi _{\theta }(s_{t}, z') \\
  &+ \delta _{\{z = z'\}} (1 - \psi _{\theta }(s_{t}, z'))\Big )
.\end {align*}

\begin {align*}
\mathbb {P}_{\theta }(s_t, a_t \mid  z) &= \pi _{\theta }(a_t \mid  s_t, z) p(s_t \mid  s_{t - 1}, a_{t - 1})
.\end {align*}

\begin {align*}
  \phi _t(z, b) = &\pi _{\theta }(a_t \mid  s_t, z) p(s_t \mid  s_{t - 1}, a_{t - 1}) \\
  &\times   \sum _{(z', b')} \phi _{t - 1}(z', b') \Big (\eta _{\theta }(z \mid  s_{t}) \psi _{\theta }(s_{t}, z') + \delta _{\{z = z'\}} (1 - \psi _{\theta }(s_{t}, z'))\Big )
.\end {align*}

