\mathbb {P}_{\theta }(s_{t + 1}, a_{t + 1} \mid  z') &= \pi _{\theta }(a_{t + 1} \mid  s_{t + 1}, z') p(s_{t + 1} \mid  s_t, a_t)
.\end {align*}

\begin {align*}
\mathcal {L}_{\text {ELBO}}(\theta ) \approx  \sum _{t=1}^{T} \log  &p_{\theta }(\mathbf {a}_{t} \mid  \mathbf {s}_{t}) + D_{\text {KL}}(q_{\theta }(m_{t} \mid  \mathbf {x}_{1:t}) \parallel  p_{\theta }(m_{t} \mid  \mathbf {s}_{t})) \\ &+ D_{\text {KL}}(q_{\theta }(z_{t} \mid  m_{t}, \mathbf {x}_{1:T}, \mathbf {a}_{1:T}) \parallel  p(z_{t})) + D_{\text {KL}}(q_{\theta }(s_{t} \mid  z_{t}, \mathbf {x}_{t}) \parallel  p_{\theta }(s_{t} \mid  s_{t-1}, m_{t-1}))
