fr:mainmatter.fr:tex:
\begin {align*}
    \phi _t(z) \beta _t(z) = \mathbb {P}(\mathcal {H} \mid  z) \mathbb {P}(z) \implies  \sum _{z} \phi _t(z)\beta _t(z) &= \sum _{z} \mathbb {P}(\mathcal {H} \mid  z) \mathbb {P}(z) \\
    &= \mathbb {P}(\mathcal {H})
  .\end {align*}

